require_once __DIR__.'/app/bootstrap.php';require_login();$employee=(int)($_GET['employee_id']??0);$month=$_GET['month']??date('Y-m');$where=['DATE_FORMAT(a.event_date,"%Y-%m")=?'];$params=[$month];if($employee){$where[]='a.employee_id=?';$params[]=$employee;}$st=db()->prepare('SELECT a.*,e.name,e.nip FROM attendance_events a JOIN employees e ON e.id=a.employee_id WHERE '.implode(' AND ',$where).' ORDER BY a.event_date');$st->execute($params);header('Content-Type: text/csv; charset=utf-8');header('Content-Disposition: attachment; filename="Rekap_Lupa_Absen_'.$month.'.csv"');echo "\xEF\xBB\xBF";$out=fopen('php://output','w');fputcsv($out,['Tanggal Kejadian','Tanggal Surat','Nama','NIP','Kategori','Pukul','Aplikasi','Alasan','Nomor Surat','Status']);foreach($st as $r)fputcsv($out,[$r['event_date'],$r['letter_date'],$r['name'],$r['nip'],categories()[$r['category']],substr($r['event_time'],0,5),$r['app_name'],$r['reason'],$r['letter_number'],approval_labels()[$r['approval_status']]]);fclose($out);
